def test_get_user_display_name_returns_default_when_profile_is_none():
    from source import get_user_display_name

    # When the profile dictionary is explicitly None, the function should
    # gracefully return the default display name "Anonymous" instead of raising
    # an exception.
    user_data = {"profile": None}
    result = get_user_display_name(user_data)

    assert (
        result == "Anonymous"
    ), f"Expected 'Anonymous' for missing profile, but got {result!r}"
